		CATBody_var spBodyOfRotLine_Neg;

		CATBody_var spBodyOnOffsetSurf, spBodyOnSplitLine_Pos, spBodyOnSplitLine_Neg, spBodyOfLineFromSplitLineEndPoint;
		CATBody *spBodyOnEndPointLineProjectOnOffsetSurf = NULL;
	
		this->CreateOffsetOfReferenceSurface(_spBodyOnBacProfile, depth, spBodyOnOffsetSurf);

